1	'use client';
2	
3	import { useState } from 'react';
4	import { useRouter } from 'next/navigation';
5	import { motion, AnimatePresence } from 'framer-motion';
6	import { useStore } from '@/lib/store';
7	
8	const CHECKLIST = [
9	  'Roof access verified with customer',
10	  'Customer informed of estimated install timeline',
11	  'Existing electrical panel sufficient',
12	  'Pricing accepted by customer',
13	];
14	
15	export function ApprovalModal() {
16	  const phase = useStore((s) => s.phase);
17	  const design = useStore((s) => s.design);
18	  const profile = useStore((s) => s.profile);
19	  const setPhase = useStore((s) => s.setPhase);
20	  const reset = useStore((s) => s.reset);
21	  const router = useRouter();
22	  const [checks, setChecks] = useState<boolean[]>(CHECKLIST.map(() => false));
23	  const [exporting, setExporting] = useState(false);
24	
25	  const open = phase === 'reviewing' && !!design;
26	
27	  const handleApprove = async () => {
28	    if (!design) return;
29	    setExporting(true);
30	
31	    for (let i = 0; i < CHECKLIST.length; i++) {
32	      await new Promise((r) => setTimeout(r, 320));
33	      setChecks((prev) => prev.map((v, idx) => (idx === i ? true : v)));
34	    }
35	    await new Promise((r) => setTimeout(r, 400));
36	
37	    try {
38	      const res = await fetch('/api/export', {
39	        method: 'POST',
40	        headers: { 'content-type': 'application/json' },
41	        body: JSON.stringify({ profile, design }),
42	      });
43	      if (res.ok) {
44	        const blob = await res.blob();
45	        const url = URL.createObjectURL(blob);
46	        const a = document.createElement('a');
47	        a.href = url;
48	        a.download = `iconic-quick-offer-${Date.now()}.pdf`;
49	        document.body.appendChild(a);
50	        a.click();
51	        a.remove();
52	        URL.revokeObjectURL(url);
53	      }
54	    } catch {
55	      // swallow — phase still advances
56	    }
57	
58	    setExporting(false);
59	    setPhase('approved');
60	
61	    // Brief pause so the user sees the "approved" state, then back to landing
62	    // with a clean store so the next demo run starts from scratch.
63	    setTimeout(() => {
64	      reset();
65	      router.push('/');
66	    }, 600);
67	  };
68	
69	  return (
70	    <AnimatePresence>
71	      {open && design && (
72	        <motion.div
73	          key="modal"
74	          initial={{ opacity: 0 }}
75	          animate={{ opacity: 1 }}
76	          exit={{ opacity: 0 }}
77	          transition={{ duration: 0.2 }}
78	          className="fixed inset-0 z-50 flex items-center justify-center bg-zinc-900/40 p-4 backdrop-blur-sm"
79	        >
80	          <motion.div
81	            initial={{ opacity: 0, scale: 0.95, y: 20 }}
82	            animate={{ opacity: 1, scale: 1, y: 0 }}
83	            exit={{ opacity: 0, scale: 0.95, y: 10 }}
84	            transition={{ duration: 0.25, ease: 'easeOut' }}
85	            className="w-full max-w-2xl overflow-hidden rounded-3xl border border-zinc-200/70 bg-white shadow-[0_24px_60px_-12px_rgba(0,0,0,0.25)]"
86	          >
87	            {/* Header */}
88	            <div className="border-b border-zinc-100 px-7 py-5">
89	              <div className="flex items-center justify-between">
90	                <div>
91	                  <h2 className="text-[20px] font-bold tracking-tight text-zinc-900">Review &amp; Approve</h2>
92	                  <p className="mt-0.5 text-[13px] text-zinc-500">
93	                    Final check before sending the quick-offer to your customer.
94	                  </p>
95	                </div>
96	                <button
97	                  onClick={() => setPhase('interactive')}
98	                  disabled={exporting}
99	                  className="rounded-full p-2 text-zinc-400 transition hover:bg-zinc-100 hover:text-zinc-600 disabled:opacity-50"
100	                >
101	                  <svg className="h-5 w-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
102	                    <line x1="18" y1="6" x2="6" y2="18" />
103	                    <line x1="6" y1="6" x2="18" y2="18" />
104	                  </svg>
105	                </button>
106	              </div>
107	            </div>
108	
109	            <div className="space-y-6 px-7 py-6">
110	              {/* Summary */}
111	              <section>
112	                <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-zinc-500">
113	                  AI recommendation
114	                </h3>
115	                <div className="space-y-2 rounded-xl bg-zinc-50 p-4">
116	                  <SummaryRow
117	                    icon="☀"
118	                    label="Modules"
119	                    value={`${design.moduleCount}× ${design.moduleBrand} ${design.moduleWattPeak} Wp`}
120	                    highlight={`${design.totalKwp.toFixed(1)} kWp`}
121	                  />
122	                  <SummaryRow icon="⚡" label="Inverter" value={design.inverterModel} />
123	                  {design.batteryCapacityKwh && (
124	                    <SummaryRow
125	                      icon="🔋"
126	                      label="Battery"
127	                      value={`${design.batteryCapacityKwh.toFixed(1)} kWh`}
128	                    />
129	                  )}
130	                  {design.heatPumpModel && (
131	                    <SummaryRow icon="🔥" label="Heat pump" value={design.heatPumpModel} />
132	                  )}
133	                  <div className="mt-3 flex items-center justify-between border-t border-zinc-200 pt-3">
134	                    <span className="text-sm font-semibold text-zinc-700">Total investment</span>
135	                    <div className="text-right">
136	                      <div className="text-lg font-bold text-zinc-900">
137	                        €{design.totalPriceEur.toLocaleString()}
138	                      </div>
139	                      <div className="text-xs text-emerald-600">
140	                        Payback {design.paybackYears.toFixed(1)} yrs · CO₂ {design.co2SavedTonsPer25y.toFixed(1)} t
141	                      </div>
142	                    </div>
143	                  </div>
144	                </div>
145	              </section>
146	
147	              {/* Checklist */}
148	              <section>
149	                <h3 className="mb-2 text-xs font-semibold uppercase tracking-wider text-zinc-500">
150	                  Pre-flight checklist
151	                </h3>
152	                <div className="space-y-2">
153	                  {CHECKLIST.map((item, i) => (
154	                    <ChecklistRow
155	                      key={item}
156	                      label={item}
157	                      checked={checks[i]}
158	                      onToggle={() =>
159	                        setChecks((prev) => prev.map((v, idx) => (idx === i ? !v : v)))
160	                      }
161	                      disabled={exporting}
162	                    />
163	                  ))}
164	                </div>
165	              </section>
166	            </div>
167	
168	            {/* Actions */}
169	            <div className="flex items-center justify-end gap-3 border-t border-zinc-100 bg-zinc-50/60 px-7 py-4">
170	              <button
171	                onClick={() => setPhase('interactive')}
172	                disabled={exporting}
173	                className="rounded-lg border border-zinc-200 bg-white px-4 py-2.5 text-sm font-medium text-zinc-700 transition hover:bg-zinc-50 disabled:opacity-50"
174	              >
175	                Adjust design
176	              </button>
177	              <button
