1	// AI Designer cockpit — assembled by Dev C, owned jointly with Dev A.
2	// This is THE page the jury sees: a 3D scene + an AI agent trace running the
3	// 22s sequence + KPI/Evidence panels + a ControlPanel for live refinement +
4	// a HITL approval modal at the end.
5	//
6	// `houseId` is one of the 3 demo houses OR `'custom'` for any address typed
7	// via the Google Places autocomplete on the landing page.
8	
9	'use client';
10	
11	import { use, useEffect } from 'react';
12	import { useRouter, useSearchParams } from 'next/navigation';
13	import { useStore } from '@/lib/store';
14	import type { HouseId } from '@/lib/types';
15	import { Scene3D } from '@/components/Scene3D/Scene3D';
16	import { Orchestrator } from '@/components/Scene3D/Orchestrator';
17	import { ProfileForm } from '@/components/AutoFillForm/ProfileForm';
18	import { AgentTrace } from '@/components/AgentTrace/AgentTrace';
19	import { KPISidebar } from '@/components/KPISidebar/KPISidebar';
20	import { ControlPanel } from '@/components/ControlPanel/ControlPanel';
21	import { ApprovalModal } from '@/components/ApprovalModal/ApprovalModal';
22	
23	interface Props {
24	  params: Promise<{ houseId: string }>;
25	}
26	
27	const KNOWN_HOUSE_IDS: HouseId[] = ['brandenburg', 'hamburg', 'ruhr'];
28	
29	function isHouseId(value: string): value is HouseId {
30	  return KNOWN_HOUSE_IDS.includes(value as HouseId);
31	}
32	
33	export default function DesignPage({ params }: Props) {
34	  const { houseId: rawHouseId } = use(params);
35	  const router = useRouter();
36	  const searchParams = useSearchParams();
37	  const phase = useStore((s) => s.phase);
38	  const selectedHouse = useStore((s) => s.selectedHouse);
39	  const customAddress = useStore((s) => s.customAddress);
40	  const design = useStore((s) => s.design);
41	  const setPhase = useStore((s) => s.setPhase);
42	
43	  const isCustom = rawHouseId === 'custom';
44	  const houseId: HouseId | 'custom' | null = isCustom
45	    ? 'custom'
46	    : isHouseId(rawHouseId)
47	      ? rawHouseId
48	      : null;
49	
50	  // Hydrate the store from URL params on mount. Demo chips link directly here
51	  // without going through landing-page state, so we have to (re)select the
52	  // house ourselves.
53	  useEffect(() => {
54	    if (houseId === null) return;
55	    if (houseId === 'custom') {
56	      // Custom address: lat/lng come in the URL, the full CustomAddress object
57	      // may already be in the store (set by AddressSearch on the landing
58	      // page). If we landed here directly with just URL params, rebuild it.
59	      const lat = parseFloat(searchParams.get('lat') ?? '');
60	      const lng = parseFloat(searchParams.get('lng') ?? '');
61	      const address = searchParams.get('address') ?? '';
62	      if (Number.isFinite(lat) && Number.isFinite(lng)) {
63	        const existing = useStore.getState().customAddress;
64	        if (!existing || existing.lat !== lat || existing.lng !== lng) {
65	          useStore.getState().setCustomAddress({
66	            formatted: address || `${lat.toFixed(4)}, ${lng.toFixed(4)}`,
67	            lat,
68	            lng,
69	            placeId: searchParams.get('placeId') ?? undefined,
70	          });
71	        }
72	      } else if (!useStore.getState().customAddress) {
73	        // No coords anywhere — bounce home so the user can pick an address.
74	        router.replace('/');
75	        return;
76	      }
77	      useStore.getState().selectHouse('custom');
78	    } else {
79	      useStore.getState().selectHouse(houseId);
80	    }
81	  }, [houseId, router, searchParams]);
82	
83	  // Demo houses: skip the manual form. As soon as the house is selected we
84	  // jump to autofilling so ProfileForm shows its 3-step typewriter.
85	  // Custom: stay in 'house-selected' so ProfileForm offers Auto / Manual.
86	  useEffect(() => {
87	    if (selectedHouse && selectedHouse !== 'custom' && phase === 'house-selected') {
88	      setPhase('autofilling');
89	    }
90	  }, [selectedHouse, phase, setPhase]);
91	
92	  // For custom addresses, seed a heuristic profile IMMEDIATELY so DemoAutoFill
93	  // has something to render and the Generate button can enable. This used to
94	  // be gated on /api/design succeeding — when /api/design returned an error
