  try {
    const res = await fetch('/api/export', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ profile, design }),
    });
    if (res.ok) {
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `iconic-quick-offer-${Date.now()}.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    }
  } catch {
    // swallow — phase still advances
  }

  setExporting(false);
  setPhase('approved');

  // Brief pause so the user sees the "approved" state, then back to landing
  // with a clean store so the next demo run starts from scratch.
  setTimeout(() => {
    reset();
    router.push('/');
  }, 600);
};

